'use client';
import { useState } from 'react';
import { useRouter } from 'next/navigation';
import { createClient } from '@/lib/supabaseClient';
export default function LoginPage(){const supabase=createClient();const router=useRouter();const [email,setEmail]=useState('');const [password,setPassword]=useState('');const [mode,setMode]=useState<'login'|'signup'>('login');const [msg,setMsg]=useState('');const [loading,setLoading]=useState(false);async function submit(){setLoading(true);setMsg('');const res=mode==='login'?await supabase.auth.signInWithPassword({email,password}):await supabase.auth.signUp({email,password});setLoading(false);if(res.error)return setMsg(res.error.message);router.push('/dashboard')}async function reset(){if(!email)return setMsg('Informe seu e-mail.');const {error}=await supabase.auth.resetPasswordForEmail(email,{redirectTo:location.origin+'/auth/login'});setMsg(error?error.message:'Enviamos um link de recuperação para seu e-mail.')}return <main className="mx-auto max-w-md px-4 py-16"><div className="card"><h1 className="text-3xl font-black">{mode==='login'?'Entrar':'Criar conta'}</h1><p className="mt-2 text-slate-600">Acesse sua evolução com segurança.</p><div className="mt-6 grid gap-3"><input className="input" placeholder="E-mail" value={email} onChange={e=>setEmail(e.target.value)}/><input className="input" placeholder="Senha" type="password" value={password} onChange={e=>setPassword(e.target.value)}/><button className="btn" disabled={loading} onClick={submit}>{loading?'Aguarde...':mode==='login'?'Entrar':'Cadastrar'}</button><button className="btn-secondary" onClick={()=>setMode(mode==='login'?'signup':'login')}>{mode==='login'?'Criar nova conta':'Já tenho conta'}</button><button className="text-sm text-brand-700" onClick={reset}>Esqueci minha senha</button>{msg&&<p className="rounded-2xl bg-slate-100 p-3 text-sm">{msg}</p>}</div></div></main>}
